   221→/* This function is used in order to push an error on the Lua stack in the
   222→ * format used by redis.pcall to return errors, which is a lua table
   223→ * with a single "err" field set to the error string. Note that this
   224→ * table is never a valid reply by proper commands, since the returned
   225→ * tables are otherwise always indexed by integers, never by strings. */
   226→void luaPushError(lua_State *lua, char *error) {
   227→    lua_Debug dbg;
   228→
   229→    /* If debugging is active and in step mode, log errors resulting from
   230→     * Redis commands. */
   231→    if (ldb.active && ldb.step) {
   232→        ldbLog(sdscatprintf(sdsempty(),"<error> %s",error));
   233→    }
   234→
   235→    lua_newtable(lua);
   236→    lua_pushstring(lua,"err");
   237→
   238→    /* Attempt to figure out where this function was called, if possible */
   239→    if(lua_getstack(lua, 1, &dbg) && lua_getinfo(lua, "nSl", &dbg)) {
   240→        sds msg = sdscatprintf(sdsempty(), "%s: %d: %s",
   241→            dbg.source, dbg.currentline, error);
   242→        lua_pushstring(lua, msg);
   243→        sdsfree(msg);
   244→    } else {
   245→        lua_pushstring(lua, error);
   246→    }
   247→    lua_settable(lua,-3);
   248→}
