   250→/* In case the error set into the Lua stack by luaPushError() was generated
   251→ * by the non-error-trapping version of redis.pcall(), which is redis.call(),
   252→ * this function will raise the Lua error so that the execution of the
   253→ * script will be halted. */
   254→int luaRaiseError(lua_State *lua) {
   255→    lua_pushstring(lua,"err");
   256→    lua_gettable(lua,-2);
   257→    return lua_error(lua);
