   268→    lua_getglobal(lua,"table");
   269→    lua_pushstring(lua,"sort");
   270→    lua_gettable(lua,-2);       /* Stack: array, table, table.sort */
   271→    lua_pushvalue(lua,-3);      /* Stack: array, table, table.sort, array */
